import{_ as a,o as l,c as e,a2 as i}from"./chunks/framework.Crpw6aS5.js";const _=JSON.parse('{"title":"沃伦·巴菲特合伙有限公司 1969-1970年致合伙人信件全文翻译","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1969年/翻译.md","filePath":"01_letters/1969年/翻译.md"}'),o={name:"01_letters/1969年/翻译.md"};function r(t,p,h,n,s,d){return l(),e("div",null,[...p[0]||(p[0]=[i('<h1 id="沃伦·巴菲特合伙有限公司-1969-1970年致合伙人信件全文翻译" tabindex="-1"><a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>合伙有限公司 1969-1970年致合伙人信件全文翻译 <a class="header-anchor" href="#沃伦·巴菲特合伙有限公司-1969-1970年致合伙人信件全文翻译" aria-label="Permalink to &quot;[[沃伦·巴菲特]]合伙有限公司 1969-1970年致合伙人信件全文翻译&quot;">​</a></h1><p>（原文为<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>1969年5月29日、10月9日、12月5日、12月26日，1970年2月25日致合伙人信件）</p><p>我们依旧保持每周5天、每天5.5小时的工作时长，全年收益大致与1957年全年涨幅持平。</p><p>1962年1月1日，我们整合了此前的有限合伙公司，搬出了卧室办公室，聘请了第一位全职员工。当时净资产为7,178,500美元，从那时到现在净资产达到104,429,431美元，我们仅新增了一名员工。1963年（资产9,405,400美元）以来，租金从3,947美元涨到5,823美元（本·罗斯纳要是知道我签了比例租金租约，绝对不会原谅我），差旅费从3,206美元涨到3,603美元，会费与订阅费从900美元涨到994美元。就算帕金森定律在起作用，局面至少还没完全失控。</p><p>回顾我们的金融资产时，我们的结论不必效仿吉普赛·罗斯·李在55岁生日盘点自身资产时说的话：“我拥有20年前拥有的一切——只是都下垂了。”</p><h2 id="其他事项" tabindex="-1">其他事项 <a class="header-anchor" href="#其他事项" aria-label="Permalink to &quot;其他事项&quot;">​</a></h2><p>尽管投资环境艰难，但办公环境极佳。唐娜、格拉迪斯、比尔和约翰组成的团队，工作高效、迅速且氛围愉悦，他们是最棒的搭档。</p><p>1969年1月1日，办公室全体员工及其配偶、子女在<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>合伙公司的投资总额超过2700万美元。各类亲戚、家人遍布合伙人名册，在我看来，你们就是我的“自家人”。</p><p>几天后你们将收到：</p><ol><li><p>税务说明函，包含1968年联邦所得税申报所需的全部合伙公司信息，此函为税务唯一有效文件。</p></li><li><p>皮特·马威克会计师事务所出具的1968年审计报告，清晰列示合伙公司运营、财务状况及各位的资本账户。</p></li><li><p>我签署的函件，列明1969年1月1日各位在合伙公司的权益，数据与审计报告完全一致。</p></li></ol><p>如本函或年内任何事宜需澄清，随时告知。下一封信预计7月10日左右，汇总上半年情况。</p><p>此致</p><p>沃伦·E·<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p><hr><h2 id="_1969年5月29日-致我的合伙人" tabindex="-1">1969年5月29日 致我的合伙人 <a class="header-anchor" href="#_1969年5月29日-致我的合伙人" aria-label="Permalink to &quot;1969年5月29日 致我的合伙人&quot;">​</a></h2><p>大约18个月前，我致信告知大家，环境与个人因素的变化，让我调整了未来的业绩目标。</p><p>我当时提及的投资环境（此后多次在信中谈及），随着时间推移愈发低迷、令人沮丧。或许我只是缺乏思维灵活性，有评论者说过40岁以上的证券分析师：“他们知道太多早已失效的道理。”</p><p>但在我看来：</p><ol><li><p>过去20年里，依赖量化分析的投资机会持续枯竭，如今几乎消失殆尽。</p></li><li><p>我们1亿美元的资产规模，进一步压缩了本就贫瘠的投资空间——单笔投资低于300万美元对整体业绩无实质影响，这基本排除了市值低于1亿美元的公司。</p></li><li><p>市场对投资业绩的狂热追捧，催生了更短期化、更具投机性的市场环境。</p></li></ol><p>1967年10月9日的信中，我提到个人因素是调整目标的核心原因。我希望摆脱自我强加的、全身心投入合伙公司的束缚，但过去18个月我彻底失败了。信中说“降低目标能减少投入”，事实并非如此。只要我还在“台前”，定期公布业绩、为众多合伙人几乎全部净资产负责，我就无法专注于合伙公司之外的事。只要公开参与投资，我就难免好胜。我不想一辈子都忙着追赶投资“兔子”，唯一的减速方式就是停下。</p><p>因此，我计划在年底前，向所有有限合伙人正式发出退休通知。合伙公司清算涉及诸多税务与法律问题，但我希望方案实现以下目标：</p><ol><li><p>最重要的是，为不愿自行打理资产的合伙人推荐替代资金管理人。我不会只说一句“祝好运”就把资金交出去，我会推荐一位我亲自为家人及需终身负责的亲友委托资金的管理人。他正直且有能力，未来业绩大概率与我相当（虽远不及过往），且对所有合伙人开放，无账户规模限制。我未来会偶尔关注其运作，但仅提供负面建议。</p></li><li><p>让所有合伙人可选择领取现金，或流动性强的证券（大概率仅一只），我认可其前景与价格，合伙人可自由变现。</p></li><li><p>让所有合伙人可选择保留在两家控股公司（多元零售公司、<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>·<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>公司）及另一只小型限制性持仓的比例权益。这些证券由我按公允价值评估，合伙人可按此估值保留权益。</p></li></ol><p>但这些证券流动性受限（受美国证监会对控股权股票、未注册股票的限制），长期内无法转让、无收益。因此清算时，你们可自由选择：持有限制性证券，或领取等值现金。我非常认可控股公司的管理层（今年<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>收购了伊利诺伊州罗克福德市的伊利诺伊国家银行信托公司，资产超1亿美元，运营极佳），希望与他们建立长期合作。我绝不为高价出售经营良好、由我敬重之人管理的企业，除非特殊情况。</p><p>我相信清算方案能实现上述目标，且不会影响各位1969年的税务规划。</p><p>我还有一个极想实现却注定落空的目标：完美收官。我不愿以糟糕的一年收尾，但1969年注定如此。我预计，扣除合伙人月度分配前，考虑到控股公司价值大幅提升（除我外合伙人可选择现金），全年业绩基本持平。即便市场大幅上涨，我们也无重大持仓受益。</p><p>今年我们的套利操作惨不忍睹，我像误闯入羽毛球比赛的小鸟。并非只有我们如此，但我们的套利配置处于历史高位。</p><p>记录错误令人不快，选择性披露更让我反感。今年的糟糕表现完全是我的责任，并非运气不佳，而是对政府政策快速变化判断失误。矛盾的是，我长期认为政府应采取此类行动（目标合理，方式未必），却没料到真会落地。投资决策中，我从不混淆“应然”与“实然”，这次若能做到，我们能少损失数百万美元。</p><p>坦白说，即便有上述因素，若有顶级投资思路，我仍会在1970年甚至1971年继续运营合伙公司。我并非想继续，只是更想以好成绩收尾。但我看不到任何能带来优质业绩的机会，也不愿拿着别人的钱碰运气。我不适应当下的市场环境，不想为了英雄式收官，毁掉过往良好记录。</p><p>因此，我们将全年逐步清算持仓，最终保留控股公司、一只投资信券、一只长期前景良好的流通证券，以及少量需数年清理的套利残仓。</p><p>我提前写这封信，替代年中信件。一旦做出决定，我希望你们立刻知晓。你们收到信后，我会在奥马哈停留一段时间，解答疑问。7月我计划前往加州。</p><p>有人会问：“你接下来打算做什么？”我暂无答案。我知道60岁的人生目标，应与20岁不同。若不脱离耗费我成年后18年全部精力的投资事业，我无法开启适配未来的新人生。</p><p>今年秋季（预计10月）我们将发函，详细说明清算流程、投资顾问推荐等事宜。</p><p>此致</p><p>沃伦·E·<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p><hr><h2 id="_1970年2月25日-致我的合伙人" tabindex="-1">1970年2月25日 致我的合伙人 <a class="header-anchor" href="#_1970年2月25日-致我的合伙人" aria-label="Permalink to &quot;1970年2月25日 致我的合伙人&quot;">​</a></h2><p>本函为免税债券基础指南，重点说明下月协助合伙人购买的债券类型与期限。若希望我们协助购买，请仔细阅读（必要时重读），此为具体建议的基础。若你不认同我关于债券类型、期限的结论（过去一两年你若反对期限判断，会是正确的），可能正确，但我们无法协助购买推荐范围外的债券。我们将全力聚焦推荐领域，无法协助或建议购买可转债、公司债、短期债券。</p><p>我已尽量精简内容，部分内容稍显专业，部分过于简化，提前致歉。我感觉试图把100页书的内容浓缩到10页，还要像漫画一样易懂。</p><hr><p>我们协助购买债券后，不再提供后续相关服务。此次协助是因你们一次性收到大额现金分配，我希望提供帮助。我无意从事投资咨询业务，3月31日后不再讨论财务事宜。</p><hr><h3 id="免税债券操作流程" tabindex="-1">免税债券操作流程 <a class="header-anchor" href="#免税债券操作流程" aria-label="Permalink to &quot;免税债券操作流程&quot;">​</a></h3><p>需要协助的合伙人，我们将通过全美市政债券经销商直接购买，债券直接确认至你名下，确认单需妥善保存作为税务凭证。你无需向经销商支票付款，经销商将债券连同汇票交付你的银行，银行从你的账户扣款支付。</p><p>二手债券结算日通常为确认日后约一周，新发行债券结算日最长可达一个月，结算日明确标注在确认单上（新债为最终确认单，非初步发行通知），结算日需确保银行账户有足额资金。若持有国库券，可指令银行提前几天出售，确保资金按时到账。利息自结算日起计算，即便经销商延迟交付。</p><p>债券以不记名形式交付（类似货币），附带息票，通常面额5000美元，可兑换为记名债券（费用视条款而定）。记名债券需你转让方可流通，债券市场几乎全部交易不记名债券，记名债券需转回不记名方可出售。因此，除非持有大量债券，我建议保留不记名形式，妥善保管，每半年剪取息票。息票可像支票一样存入银行账户，25万美元债券约50张凭证，每年需6-8次前往保险柜剪票存入。</p><p>也可在银行开设托管账户，年费适中，银行代为保管债券、收取利息、保存记录。例如25万美元投资组合，托管年费约200美元，可咨询商业银行信托部门了解服务与费用，否则需配备保险柜。</p><h3 id="税务" tabindex="-1">税务 <a class="header-anchor" href="#税务" aria-label="Permalink to &quot;税务&quot;">​</a></h3><p>免税债券息票利息免征联邦所得税，联邦所得税税率30%的投资者，6%的免税债券收益等价于8.5%的应税债券收益。因此，对多数合伙人（除未成年人或部分退休人士），免税债券比应税债券更具吸引力。收入较低、资本充足的投资者，可配置应税债券（将应税收入提升至25%-30%税率档）+免税债券，实现税后收益最大化，必要时我们可协助平衡配置。</p><p>州所得税更为复杂。内布拉斯加州州所得税按联邦所得税比例计算，免税债券利息免征州税。据我了解，纽约州、加州本州发行的免税债券免征州税，外州债券需缴纳州税；纽约市对本州免税债券免征市税，外州债券征税。我非州税专家，不跟踪各地税法变化，建议咨询当地税务顾问。外州债券需缴纳的州或市所得税，可在联邦所得税中抵扣，具体金额因人而异。部分州对所有免税债券或外州债券征收无形资产税，内布拉斯加州无此税，其他州无法逐一说明。</p><p>折价购买的债券到期出售或兑付，差价按资本利得或损失处理（投资与税务的通用规则均有少量例外，若影响我们推荐的证券，会及时告知），这会因未来资本利得税税率与个人税务状况，降低税后净收益率。后续我们将讨论资本利得税对折价债券与全息票债券吸引力的影响。</p><p>最重要的一点：法律规定不明确，但若你有或计划申请通用银行贷款或其他债务，建议不要持有免税债券。为购买或持有免税债券而产生的贷款利息，不得税前扣除，未来法律解释大概率会扩大适用范围。例如，持有免税债券的同时，房地产抵押贷款利息（除非贷款用于购买市政债券）可税前扣除；但持有通用银行贷款（即便用于购买股票、壁球馆等，且免税债券未抵押），同时扣除贷款利息并持有免税债券，存在税务风险。建议还清银行贷款后再持有免税债券，具体问题请咨询税务顾问，我仅提醒潜在风险。</p><h3 id="流动性" tabindex="-1">流动性 <a class="header-anchor" href="#流动性" aria-label="Permalink to &quot;流动性&quot;">​</a></h3><p>免税债券与普通股、公司债差异极大，债券种类数十万计，多数持有者极少，严重限制活跃市场发展。纽约、费城等城市融资时，会发行数十种不同期限的债券，同一城市、同利率、不同到期日的债券为不同品种，无法互换，卖家需找到对应品种的买家。仅纽约市就有约1000种未清偿债券，内布拉斯加州格兰德艾兰市有75种，单只品种平均规模10万美元，平均持有者6-8人。因此，所有品种无法随时报价，买卖价差可能极大。你无法随时买到指定的格兰德艾兰市债券，即便找到卖家，价格也未必合理。</p><p>而俄亥俄州收费公路、伊利诺伊州收费公路等单只品种规模达2亿美元，持有者数千人，流动性极高。</p><p>我认为流动性主要取决于三大因素（按重要性排序）：</p><ol><li><p>单只品种规模；</p></li><li><p>发行方规模（俄亥俄州10万美元品种比小镇10万美元品种流动性更高）；</p></li><li><p>发行方资质。</p></li></ol><p>债券销售资源主要集中在新发行债券，每周新债发行规模超2亿美元，分销体系全力销售。我认为，初始销售期结束后，市场未充分定价流动性差异，部分债券买卖价差可达15%。我们不会为你购买此类流动性极差的债券，推荐的债券买卖价差通常为2%-5%，对长期投资者无实质阻碍，核心是远离流动性极低的债券（当地经销商往往有更高销售激励）。</p><h3 id="重点购买领域" tabindex="-1">重点购买领域 <a class="header-anchor" href="#重点购买领域" aria-label="Permalink to &quot;重点购买领域&quot;">​</a></h3><p>我们将重点配置以下领域：</p><ol><li><p>大型创收公共实体债券，如收费公路、电力区、水区等。此类品种流动性高、可量化分析，部分偿债基金等条款未被市场充分定价。</p></li><li><p>工业发展局债券，公共实体持有资产并租赁给私营企业。例如俄亥俄州洛雷恩市为美国钢铁公司持有8000万美元项目，发展局发行债券融资，与美国钢铁签订净租赁协议覆盖债券偿付。债券无州市政府信用背书，仅依赖租赁企业信用。众多顶级企业支持此类债券，因税法变化，新发行规模较小（单项目500万美元以下）。曾长期受市场偏见，收益率远高于内在信用水平，偏见逐渐消退，溢价收窄，但仍为优质领域。我们的保险公司大部分债券配置于此。</p></li><li><p>公共住房管理局债券，追求最高评级免税债券的选择，实质由美国政府担保，评级AAA。若本州税收优惠要求配置本州债券，且前两类无法满足需求，我会优先选择此类债券，无需分散，均为顶级信用。</p></li><li><p>各州直接或间接债券。</p></li></ol><p>我不购买大城市债券，无法分析纽约、芝加哥、费城等城市信用（朋友调侃纽瓦克市发债利率过高，连黑手党都嫌名声差）。你对纽约市债券的分析，与我水平相当。我的债券投资逻辑与股票一致：不懂就放弃，错过不理解的机会不可惜，只需确保懂的机会能带来合理回报，且决策正确。</p><p>多数合伙人配置5-10只债券，若要求仅限本州，品种可能更少（或仅住房管理局债券）。单只购买金额不低于2.5万美元，优先大额配置，小额债券转售时通常大幅折价，债券销售商不会告知此点，但出售时会体现。二手市场小额品种若价格极具优势，可例外配置。</p><h3 id="可赎回债券" tabindex="-1">可赎回债券 <a class="header-anchor" href="#可赎回债券" aria-label="Permalink to &quot;可赎回债券&quot;">​</a></h3><p>我们不购买发行方有权以明显有利自身的条款赎回的债券。令人惊讶的是，许多人购买40年期债券，发行方5-10年后可小幅溢价赎回，本质是：对发行方有利（对投资者不利）则持有40年，对投资者有利（对发行方不利）则5年兑付，条款极不公平，只因投资者无法理解，经销商也不提醒。极具讽刺的是，此类条款极差的债券，与无赎回权的同类债券收益率几乎相同。</p><p>需指出，内布拉斯加州多数债券赎回条款极不公平，却未提供更高收益率。</p><p>规避此问题的方式：购买无赎回权债券；或购买折价债券，发行方赎回价远高于你的成本，赎回影响极小。例如以60美元买入、103美元赎回的债券，赎回成本可忽略。但以100美元买入洛杉矶水务局债券，1999年到期兑付100美元、或1974年按104美元赎回（均对发行方有利），在同类无不公平条款债券收益率相当的情况下，此举极为愚蠢，而此类债券仍在持续发行。我详细说明此点，只因大量投资者对此毫无认知，经销商也不会告知。</p><h3 id="期限与债券数学" tabindex="-1">期限与债券数学 <a class="header-anchor" href="#期限与债券数学" aria-label="Permalink to &quot;期限与债券数学&quot;">​</a></h3><p>许多人购买债券时，按持有期限、寿命选择到期日，此思路并非不合理，但非最优逻辑。期限选择核心依据：</p><ol><li><p>收益率曲线形态；</p></li><li><p>未来利率水平预期；</p></li><li><p>可承受的价格波动幅度。</p></li></ol><p>其中第二点最重要，也最难判断。</p><p>先说收益率曲线：资质相同的债券，期限不同利率不同。当前顶级债券，6-9个月期收益率4.75%，2年期5.00%，5年期5.25%，10年期5.50%，20年期6.25%。长期利率远高于短期，为陡峭正向曲线。美国国债市场近期为负向曲线，长期国债收益率持续低于短期。收益率曲线有时平坦，有时10年期前正向、之后走平。需理解其波动极大，当前处于高正向区间，这意味着长期债券的期限溢价高于历史多数时期。若收益率长期稳定，无论持有期限长短，长期债券收益优于短期债券。</p><p>第二点是未来利率预期，对此预测者往往迅速出错。一年前我认为利率不低，事实证明完全错误；当前我认为利率合理，可能再次出错。但必须做出决策，现在买入短期债券，未来再投资利率大幅走低，同样可能犯错。</p><p>第三点是价格波动承受力，涉及债券数学，需理解核心原则。假设收益率曲线平坦、债券无赎回权，当前利率5%，买入2年期与20年期债券。一年后利率降至3%，不计价差、佣金等，2年期债券（剩余1年）售价1019.6美元，20年期债券（剩余19年）售价1288.1美元，买家持有可获得3%收益率。若利率升至7%，2年期债券售价981美元，20年期债券售价791.6美元，买家需折价补偿以获得7%收益率。</p><p>原则简单：利率波动越大、债券期限越长，到期前价值波动越大。需注意，若5%利率的长期债券5年后可按面值赎回，利率降至3%时涨幅仅约7%，利率升至7%时跌幅不变，凸显赎回条款的不公平。</p><p>20多年来，免税债券利率持续走高，长期债券投资者持续亏损，但这不代表现在买长期债券错误，只是过去长期单边下跌，投资者更关注下行风险，忽视上行潜力。</p><p>若未来利率涨跌概率均等、收益率曲线陡峭正向，长期无赎回权债券的投资赔率优于短期债券，这是我当前的结论，因此计划配置10-25年期债券。若你有期限偏好，我们可尽量满足；若偏好短期债券，我们无法协助，因未覆盖该领域。</p><p>决定购买20年期债券前，请重读利率变化对价格的影响。持有至到期可获得约定利率，但提前出售，将受上述数学规律影响。债券价格也会因资质变化波动，但免税领域，资质影响远小于利率整体变化。</p><h3 id="折价债券与全息票债券" tabindex="-1">折价债券与全息票债券 <a class="header-anchor" href="#折价债券与全息票债券" aria-label="Permalink to &quot;折价债券与全息票债券&quot;">​</a></h3><p>如上述讨论，19年期债券若要获得7%收益率，可选择新发19年期7%息票债券，或5%息票、791.6美元折价买入的债券，19年后兑付1000美元，两者复利收益率完全相同，数学等价。但免税债券中，70美元息票全部免税，折价债券每年50美元免税利息，19年后获得208.4美元资本利得。现行税法下，资本利得税从最低（利得为唯一收入）到最高（大额资本利得叠加）超过70美元（1972年及以后资本利得税率35%，高收入者略高），此外可能需缴纳州资本利得税。</p><p>显然，同等条件下，投资者不会以791.6美元买入5%息票债券，认为与1000美元买入7%息票债券等价，市场也是如此。因此，资质、期限相同的债券，低息票折价债券的总收益率远高于高息票全价债券。</p><p>有趣的是，对多数投资者，折价债券的高总收益率足以弥补未来潜在税负，原因有三：</p><ol><li><p>无人知晓债券到期时的税法，普遍预期未来税率更高。</p></li><li><p>791.6美元买入5%息票、19年期债券，当期收益率约6.3%，剩余收益来自到期兑付的差价，而投资者更偏好当期高现金收益。</p></li><li><p>最重要的是，1969年税制改革改变银行税务处理，银行退出折价免税债券市场。银行是免税债券的最大买家，退出某一细分市场会对供需产生重大影响，这为个人投资者提供了折价债券市场的优势，尤其是到期或出售时税率较低的投资者。</p></li></ol><p>若能显著提升税后收益率（合理预估你的未来税务状况），我将为你配置折价债券。部分合伙人偏好全息票债券，即便收益率更低，仅为最大化当期现金收益，若告知此偏好，我们将仅配置全息票（或接近全息票）债券。</p><h3 id="操作流程" tabindex="-1">操作流程 <a class="header-anchor" href="#操作流程" aria-label="Permalink to &quot;操作流程&quot;">​</a></h3><p>3月我将全天在办公室（3月7日周六除外），欢迎预约面谈或电话沟通，请提前与格拉迪斯或我预约。唯一要求是，沟通前请尽量理解本函内容，否则逐一解释将耗费巨大精力。</p><p>若决定让我们协助购买债券，请告知：</p><ol><li><p>是否因本州税收原因，仅限购买本州债券；</p></li><li><p>是否仅限全息票债券，或由我们判断最优选择；</p></li><li><p>10-25年期内的期限偏好，或由我们判断；</p></li><li><p>拟投资金额（实际配置可能略低，绝不超额）；</p></li><li><p>债券扣款银行。</p></li></ol><p>购买债券后，我们将电话或信函告知。比尔与约翰负责大部分机械操作，我们所有人均无任何财务利益。若有操作问题，请咨询约翰或比尔，我届时事务繁忙，他们更熟悉具体流程。3月31日后，我预计数月不在办公室，请在此前沟通。所有购买可能延续至4月，由比尔负责完成。</p><p>需理解，债券品种极为多样，无法确定具体购买标的。免税债券市场有时更像房地产而非股票，数十万种品种可比性各异，部分无卖家、部分卖家犹豫、部分卖家急切，最优选择取决于品种资质、适配需求、卖家意愿。对比基准始终是每周发行的新债，但二手市场机会可能更优，需报价后方能确定。</p><p>市场虽有波动，20年期免税债券（住房管理局债券除外）税后收益率达到6.5%左右无难度。</p><p>此致</p><p>沃伦·E·<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p><p>需要我把这份翻译<strong>整理成纯文本无格式版</strong>，方便你直接复制使用吗？</p><blockquote><p>（注：文档部分内容可能由 AI 生成）</p></blockquote>',94)])])}const m=a(o,[["render",r]]);export{_ as __pageData,m as default};
